-- Enrichment marathon batch: Datree, Datrium, DB Designer, DB-IP, DeaDBeeF, Dead Man's Snitch, Dealpath, debugmail.io

-- ── Datree ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Datree was a policy-enforcement and configuration-validation tool that scanned Kubernetes manifests and Infrastructure-as-Code files for misconfigurations before they reached production. It shipped as a CLI plus a hosted policy dashboard used in CI/CD pipelines and pre-commit hooks. The commercial company behind Datree closed in July 2023, and its GitHub repository was archived as read-only in June 2024, so the product is no longer actively developed, supported, or sold.$q$, short_description),
  pricing_model = COALESCE($q$Discontinued as a commercial SaaS product as of 2023; the remaining CLI codebase is free and open source under the Apache 2.0 license$q$, pricing_model),
  starting_price = COALESCE($q$Not applicable, the commercial product has been discontinued and the open-source CLI is free to run in offline mode$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Company closed in July 2023 after operating with an estimated 11-50 employees at its peak$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel (historical, prior to the company closing)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Datree Review 2026: What Happened and Current Status$q$, seo_title),
  seo_meta_description = COALESCE($q$Datree was a Kubernetes and IaC policy-enforcement tool. See what it did, why the company closed in 2023, and where to look for active alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Datree was a policy-enforcement and configuration-validation platform built specifically for Kubernetes manifests and Infrastructure-as-Code files such as Helm charts, Kustomize configurations, and Terraform. Founded in 2017 by Shimon Tolts and Eyar Zilberman and headquartered in Tel Aviv, Israel, the company raised about 11 million US dollars across a seed round from TLV Partners in 2018 and an 8 million dollar Series A led with participation from Blumberg Capital in 2020. The core product was an open-source command-line interface, distributed on GitHub under the datreeio organization, that developers ran locally or inside CI/CD pipelines to catch Kubernetes misconfigurations, such as missing resource limits, disallowed image tags, or violations of best-practice rules, before manifests were applied to a cluster. Datree paired the CLI with a hosted web dashboard where teams could author, share, and centrally enforce custom policies, view historical validation results across repositories, and integrate checks into GitHub, GitLab, Jenkins, and other pipelines. It positioned itself as an end-to-end, code-to-cloud guardrail for platform and DevOps engineering teams who needed to prevent bad Kubernetes configurations from ever reaching production, complementing runtime security tools rather than replacing them. Datree integrated with policy-as-code engines and shipped a built-in library of best-practice rules covering workload reliability, security posture, and Kubernetes API conventions, and it supported writing custom rules in YAML or via Open Policy Agent. As of 2026, Datree is no longer an active commercial product. The company that built and sold it shut down in July 2023 after roughly six years in business without reaching sustainable profitability or being acquired; despite being informally linked in some third-party listings to acquirers such as Spectral or Check Point, no verifiable evidence confirms an acquisition of Datree itself, and the company's own GitHub documentation describes the closure as a shutdown rather than a sale. The GitHub repository datreeio/datree was subsequently archived by its owner on June 6, 2024, meaning it is now read-only and accepts no further code changes, bug fixes, or security patches. The hosted dashboard, centralized policy registry, and related cloud services tied to the commercial offering are no longer available. Existing users are directed to run the Datree CLI as a standalone, offline tool with a reduced feature set, relying on locally stored policies rather than the cloud dashboard. The underlying codebase remains publicly accessible under the Apache 2.0 open-source license, so technically minded teams can still fork it, self-host validation logic, or extract individual policy rules, but there is no vendor support, roadmap, or security patching going forward. For a directory or comparison context in 2026, Datree should be described accurately as a discontinued commercial product and an archived, unmaintained open-source project, useful mainly as a historical reference point when evaluating currently active Kubernetes policy tools such as Kyverno, OPA Gatekeeper, Conftest, or Checkov, all of which continue to receive active development and community support.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e23e4ddb-c07a-4b99-a76f-d5c1db4f834b';

