-- ── Datrium ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Datrium was a hybrid cloud data platform and converged infrastructure company known for its DVX system, which paired on-premises compute nodes with cloud-based data management and built-in disaster recovery. VMware acquired Datrium in 2020 for its disaster-recovery technology, then discontinued the DVX hardware and hyperconverged software line within weeks of closing the deal. Datrium's disaster-recovery-as-a-service technology lives on today as VMware Cloud Disaster Recovery, now sold under Broadcom-owned VMware.$q$, short_description),
  pricing_model = COALESCE($q$Discontinued as a standalone company and product line; its surviving DRaaS technology is sold as VMware Cloud Disaster Recovery under VMware or Broadcom subscription pricing$q$, pricing_model),
  starting_price = COALESCE($q$Not applicable, Datrium as a standalone product no longer exists$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Not publicly disclosed after being absorbed into VMware in 2020; reported to have roughly a few hundred employees at the time of acquisition$q$, company_size),
  headquarters = COALESCE($q$Sunnyvale, California, United States (historical, prior to the 2020 VMware acquisition)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Datrium Review 2026: History, VMware Acquisition and Status$q$, seo_title),
  seo_meta_description = COALESCE($q$Datrium built hybrid cloud converged infrastructure before VMware acquired it in 2020. Learn what happened to Datrium and where its technology lives today.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Datrium was a hybrid cloud data platform and converged infrastructure company founded in 2012 and headquartered in Sunnyvale, California. Its flagship product, the DVX system, combined commodity on-premises compute nodes running a hyperconverged software stack with a cloud-connected data management layer, aiming to let enterprises run virtual machines on-premises while keeping backup, disaster recovery, and long-term data retention in the cloud without needing separate backup appliances or software. Datrium marketed DVX as a way to collapse primary storage, backup, and disaster recovery into a single platform, and it later expanded into a pure disaster-recovery-as-a-service offering aimed specifically at protecting VMware vSphere workloads by replicating them to the cloud. On July 1, 2020, VMware announced its intent to acquire Datrium, and the deal closed later that year for a total purchase price, net of cash acquired, of about 137 million US dollars, made up primarily of roughly 25 million dollars in identifiable intangible assets and about 91 million dollars in goodwill. VMware's stated rationale was to strengthen its VMware Site Recovery and broader disaster-recovery-as-a-service portfolio by adding a cost-optimized option for protecting data stored either on-premises or on Amazon Web Services infrastructure. Notably, VMware moved quickly after closing the acquisition: in August 2020, just over a month later, VMware discontinued the Datrium DVX hyperconverged hardware and software line effective immediately, stopping new hardware orders from new customers, allowing existing customers to place additional orders only through October 31, 2020, and ultimately winding down support for existing DVX deployments by 2023. Rather than continuing to sell Datrium's on-premises hyperconverged infrastructure, VMware chose to keep and rebrand only the disaster-recovery-as-a-service component of Datrium's technology. That surviving piece was relaunched as VMware Cloud Disaster Recovery, a cloud-native DRaaS offering that, unlike the original Datrium DRaaS, no longer requires Datrium DVX hardware on-premises and instead works with any storage supported by VMware vSphere. As of 2026, Datrium does not exist as an independent company, brand, or purchasable product; VMware itself was subsequently acquired by Broadcom in November 2023, meaning the technology lineage that started at Datrium now sits several ownership layers deep inside Broadcom's VMware Cloud Foundation and disaster-recovery portfolio. For anyone researching Datrium today, whether for a directory listing, a competitive analysis, or historical due diligence, the accurate framing is that Datrium was a converged infrastructure and hybrid cloud vendor whose hardware line was fully discontinued in 2020 and whose remaining intellectual property is embedded in VMware Cloud Disaster Recovery, a Broadcom-owned product, rather than being available as a standalone Datrium offering.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a';

