-- ── DB-IP ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$DB-IP is an IP geolocation database and API service operated by Eris Networks, providing location, network, and threat-intelligence data tied to IPv4 and IPv6 addresses. It has offered geolocation services since 2010 and covers the entire IPv4 and IPv6 address space with more than 45 million address blocks across more than 215,000 cities worldwide. The company sells tiered API subscriptions plus downloadable offline databases, and offers a free Lite database tier for lower-accuracy, non-commercial use.$q$, short_description),
  pricing_model = COALESCE($q$Tiered monthly API subscriptions plus one-time or subscription downloadable database licenses, with a free Lite database tier$q$, pricing_model),
  starting_price = COALESCE($q$Approximately 8.29 euros per month for the Starter Basic API plan$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Not publicly disclosed, operates as a small, focused data provider$q$, company_size),
  headquarters = COALESCE($q$Perros-Guirec, France (Eris Networks S.A.S)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$DB-IP Review 2026: IP Geolocation Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$DB-IP offers IP geolocation and network intelligence data via API and downloadable databases. Compare its pricing, accuracy, and features for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$DB-IP is an IP geolocation and network intelligence data provider operated by Eris Networks S.A.S, headquartered in Perros-Guirec, France, that has offered geolocation services since 2010. Its core product maps IP addresses to real-world location and network attributes, covering the entire IPv4 and IPv6 address space with a database of more than 45 million address blocks spanning over 2 million unique locations across more than 215,000 cities worldwide. DB-IP reports accuracy above 97 percent at the city level and 99.99 percent at the country level globally, figures the company positions as competitive with larger geolocation vendors. Data is delivered in two main ways: a real-time API that developers query per request, and downloadable offline database files (in formats such as MMDB and CSV) that customers can integrate directly into their own infrastructure without making network calls, which is useful for high-volume or latency-sensitive applications. The API and database products are organized into three escalating data tiers. The Basic tier returns core location information such as country, region, city, GPS coordinates, district, zip code, time zone, and a Geonames unique place identifier. The Core tier includes everything in Basic and adds detailed network and connectivity data, including autonomous system (AS) number and name, ISP and organization name, and connection type. The Extended tier includes everything in Core and layers on security-relevant data such as proxy and crawler detection and threat-level assessment, aimed at fraud prevention, content localization, and access-control use cases. For the Basic API specifically, DB-IP publishes three subscription levels: a Starter plan around 8.29 euros per month covering roughly 2,000 to 50,000 requests per day with HTTPS access, localization in more than fifty languages, batch queries of up to 256 IPs, a single CORS domain, and email support; a Premium plan around 99.90 euros per month covering 200,000 to 1,000,000 requests per day with up to five CORS domains, a 99.95 percent uptime guarantee, and priority support; and an Enterprise plan around 499.90 euros per month offering unlimited daily requests, unlimited batch queries, unlimited CORS domains, a 99.99 percent uptime guarantee, dedicated infrastructure, and priority support. Core and Extended API tiers, along with downloadable database products, are priced separately and generally require checking DB-IP's site or contacting sales for current rates, since pricing for higher data tiers is not uniformly published in one place. Localization is a notable differentiator: DB-IP supports country, region, district, and city name localization in more than fifty languages for its API responses, while the downloadable MMDB-format databases include localized place names in a smaller set of major languages such as English, French, German, Spanish, Portuguese, Chinese, Japanese, Russian, Persian, and Korean. DB-IP also offers a free IP-to-City Lite database aimed at developers and non-commercial or lower-budget use cases who need basic city-level geolocation without a paid subscription, though free-tier accuracy and update frequency are reduced compared to paid commercial databases. As a directory entry in 2026, DB-IP is best understood as a mid-market IP geolocation and network intelligence provider competing with vendors like MaxMind and IPinfo, differentiated primarily by its extensive language localization support, tiered data depth (Basic, Core, Extended), and the flexibility of choosing between a live API and self-hosted offline database files.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6776ca43-0c85-42d6-ab67-97d33ece86d2';

