-- ── DeaDBeeF ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$DeaDBeeF is a free, open-source, plugin-based audio player originally built for Linux and other Unix-like systems, with additional builds for Windows and macOS. First released in 2009, it emphasizes a modular architecture where nearly every feature, from format decoders to on-screen notifications, is delivered through plugins that users can enable or disable. It supports a very wide range of audio formats and is popular among Linux users who want a lightweight, highly customizable music player.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source, no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Not applicable, DeaDBeeF is a community-maintained open-source project rather than a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable, distributed open-source project with no corporate headquarters$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$DeaDBeeF Review 2026: Features and How It Compares$q$, seo_title),
  seo_meta_description = COALESCE($q$DeaDBeeF is a free, open-source, plugin-based audio player for Linux. See its supported formats, plugin system, and how it compares to other music players.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$DeaDBeeF is a free and open-source, plugin-based audio player first released in August 2009, primarily aimed at Linux and other Unix-like operating systems but also available on Windows and, less commonly, macOS. The name is a reference to the classic hexadecimal debug value 0xDEADBEEF, a nod to the project's developer-oriented, tinkerer-friendly design philosophy. The defining characteristic of DeaDBeeF is its modular plugin architecture: rather than shipping as a fixed, monolithic application, the player exposes almost all of its functionality, including format decoders, output backends, user-interface behavior, and on-screen notifications, as individual plugins that users can enable, disable, or replace, letting each installation be tailored precisely to what a given user wants without carrying unnecessary bloat. Because of this architecture, DeaDBeeF supports an unusually broad range of audio formats out of the box or via plugins, including MP3, OGG, FLAC and OGA, APE, WAV, WavPack, AAC and M4A, ALAC, Musepack, TTA, WMA, SHN, and tracker or chiptune formats such as SID, NSF, MOD, S3M, VTX, VGM and VGZ, PSF, and MIDI, plus audio CDs, and it can additionally decode any format supported by underlying libraries like ffmpeg, dumb, Game Music Emu, libsndfile, and adplug when those plugins are installed. Notable user-facing features include native CUE sheet handling for gapless playback of albums ripped as a single file, an on-screen-display notification plugin that pops up track information when a song changes, an album-art plugin capable of pulling artwork from multiple online and local sources, and the ability to play music directly from ZIP archives without extracting them first. The interface itself is customizable, and later versions, such as the 1.10.x release series, moved to GTK3 as the default toolkit while adding features like FLAC network streaming support, a lyrics plugin, and improved album-art display modes, reflecting ongoing incremental development by its maintainer and contributor community. As a genuinely community-driven open-source project rather than a commercial company, DeaDBeeF has no pricing, no company headquarters, and no formal company size; it is developed collaboratively, distributed under an open-source license, and made available through package managers on most major Linux distributions, as well as via direct downloads and unofficial PPAs for Ubuntu-based systems, and through SourceForge, where its official project page and downloads are hosted. It competes in the same general space as other lightweight, format-agnostic Linux audio players such as Audacious, Clementine, and Strawberry, but differentiates itself specifically through the depth of its plugin ecosystem and its especially wide native format support, including many niche tracker and chiptune formats rarely supported out of the box by mainstream music players. For a directory entry in 2026, DeaDBeeF should be positioned as a free, technically capable, and highly configurable audio player best suited to Linux users, audiophiles, and retro-format enthusiasts who value plugin-level customization over a polished, opinionated, all-in-one media player experience, and who are comfortable configuring plugins to get exactly the feature set they want rather than relying on a fixed built-in toolset.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e41fd154-3522-4aa5-8b80-838519aa792f';

