INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Kubernetes manifest validation$q$, $q$Scanned YAML manifests against built-in and custom rules covering reliability, security, and Kubernetes API best practices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$CI/CD pipeline integration$q$, $q$Ran as a step in GitHub Actions, GitLab CI, Jenkins, and other pipelines to block non-compliant manifests before merge or deploy.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Custom policy authoring$q$, $q$Let teams define their own rules in YAML or via Open Policy Agent to reflect organization-specific standards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Centralized policy dashboard$q$, $q$Offered a hosted web interface for managing policies and viewing validation history across repositories, now discontinued.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Pre-commit and local CLI checks$q$, $q$Allowed developers to validate manifests on their own machines before ever pushing code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Schema validation$q$, $q$Checked manifests against official and custom Kubernetes JSON schemas to catch structural errors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Rule library$q$, $q$Shipped with a curated set of best-practice rules that could be enabled or disabled per team.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Open-source CLI$q$, $q$Released the core scanning engine under the Apache 2.0 license, still downloadable and runnable in offline mode.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Was straightforward to add as a single step in existing CI/CD pipelines$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Covered a broad, curated library of Kubernetes best-practice rules out of the box$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Supported custom policies for teams with organization-specific standards$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Free, open-source CLI remains downloadable and can still run basic offline checks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Clear, human-readable violation output that made it easy to see exactly what to fix$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$The company has shut down and the product receives no further updates or security patches$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$The GitHub repository is archived and closed to new contributions as of June 2024$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$The hosted dashboard, centralized policy registry, and cloud sync are no longer available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Teams relying on it today are running unsupported software with no vendor accountability$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$No clear migration tooling was provided to move historical policies to another platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Rule coverage has not evolved with newer Kubernetes API versions since the shutdown$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Is Datree still available in 2026$q$, $q$The open-source CLI code is still publicly downloadable on GitHub, but the commercial product, hosted dashboard, and company behind it are no longer operating. The repository was archived as read-only in June 2024.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Was Datree acquired by Spectral or Check Point$q$, $q$No verifiable evidence confirms this. Check Point acquired Spectral, a separate Israeli developer-security startup, in 2022, but Datree's own documentation describes its July 2023 closure as a shutdown, not an acquisition.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Can I still use the Datree CLI today$q$, $q$Yes, the CLI can still be run locally in offline mode for basic Kubernetes manifest checks, but without the cloud dashboard, centralized policy registry, or vendor support that the commercial product once provided.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$What did Datree cost when it was active$q$, $q$Datree offered a free-forever CLI tier alongside paid team and enterprise plans with centralized policy management, though exact historical pricing is no longer published since the product was discontinued.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$What should teams use instead of Datree$q$, $q$Actively maintained alternatives for Kubernetes policy enforcement include Kyverno, Open Policy Agent with Gatekeeper, Conftest, and Checkov.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Who founded Datree$q$, $q$Datree was founded in 2017 by Shimon Tolts and Eyar Zilberman and was headquartered in Tel Aviv, Israel.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Does Datree still receive security patches$q$, $q$No. Because the repository is archived, it does not receive security patches, bug fixes, or new Kubernetes API compatibility updates.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Is there a risk to using Datree in production pipelines now$q$, $q$Yes, since the tool is unmaintained, teams should treat it as a legacy stopgap at most and plan a migration to an actively supported policy-enforcement tool.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Historical reference for Kubernetes policy tooling$q$, $q$Useful as a case study of an early Kubernetes policy-enforcement product when researching the evolution of the category.$q$, $q$DevOps and platform engineering teams researching tooling history$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Offline manifest linting$q$, $q$The archived open-source CLI can still be run locally as a basic, no-frills Kubernetes manifest linter.$q$, $q$Individual developers wanting a quick, free local check$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$Migration planning$q$, $q$Teams still running the legacy Datree CLI can use this profile to understand why it is time to migrate to an actively maintained alternative.$q$, $q$Engineering leads auditing unmaintained dependencies in CI/CD pipelines$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$what-datree-did$q$, $q$What Datree Did$q$, 2, ARRAY[$q$Datree provided automated policy checks for Kubernetes YAML manifests and related Infrastructure-as-Code files, catching problems like missing health checks, overly permissive security contexts, or non-compliant naming conventions before deployment.$q$, $q$The tool combined a free, open-source CLI with an optional hosted dashboard that let teams write and enforce custom policies across repositories and pipelines, effectively acting as a linter and guardrail layer between a developer's local machine and a production Kubernetes cluster.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$why-datree-shut-down$q$, $q$Why Datree Is No Longer Active$q$, 2, ARRAY[$q$Datree's parent company ceased commercial operations in July 2023 after failing to reach sustainable profitability, and no acquisition of the business has been publicly confirmed despite some third-party company databases loosely associating it with other Israeli security vendors.$q$, $q$The project's GitHub repository was formally archived on June 6, 2024, closing it to new commits, issues, and security fixes. This means teams still relying on Datree in production pipelines are running unmaintained software and should plan a migration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', $q$alternatives-to-consider$q$, $q$What Teams Use Instead$q$, 2, ARRAY[$q$Teams that previously used Datree for Kubernetes policy enforcement have generally migrated to actively maintained tools such as Kyverno, Open Policy Agent with Gatekeeper, Conftest, or Checkov, which cover similar use cases with ongoing community and vendor support.$q$, $q$Because Datree's dashboard and centralized policy registry are gone, any residual use of the Datree CLI today should be treated as a purely local, offline linting step rather than a full policy-enforcement platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e23e4ddb-c07a-4b99-a76f-d5c1db4f834b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Converged compute and cloud data management$q$, $q$DVX combined on-premises compute nodes with a cloud-connected data management layer for primary storage, backup, and disaster recovery in one system.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Built-in backup and disaster recovery$q$, $q$Eliminated the need for separate backup appliances by handling data protection natively within the platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$VMware vSphere integration$q$, $q$Was purpose-built to protect and replicate VMware virtual machine workloads.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Cloud-based long-term retention$q$, $q$Pushed older backup data to the cloud for cost-effective long-term storage rather than keeping it on local hardware.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Disaster-recovery-as-a-service$q$, $q$Offered a pure DRaaS product that replicated on-premises workloads to the cloud without requiring a secondary physical data center.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Hyperconverged hardware appliances$q$, $q$Sold purpose-built DVX hardware appliances, discontinued by VMware in August 2020.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Pioneered a genuinely novel architecture that split compute and data management between on-premises and cloud$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Simplified disaster recovery for VMware-heavy environments by removing the need for a full secondary data center$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Its surviving DRaaS technology continues to be developed and supported today as VMware Cloud Disaster Recovery$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Was tightly integrated with VMware vSphere, which many enterprises already ran$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Received meaningful venture backing and industry attention prior to its acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$The Datrium brand and DVX hardware line no longer exist; VMware discontinued them in August 2020$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Existing DVX customers had a hard cutoff for ordering new hardware and a defined end of support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$The company is not independently operable or purchasable today under the Datrium name$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Its surviving technology is now several ownership layers removed, sitting inside Broadcom-owned VMware$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Historical Datrium documentation and support resources are largely superseded by VMware Cloud Disaster Recovery materials$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Buyers researching Datrium in 2026 cannot get a current quote, demo, or support contract under that name$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Does Datrium still exist as a company in 2026$q$, $q$No. Datrium was acquired by VMware in 2020 and no longer operates as an independent company or brand.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Can I still buy Datrium DVX hardware$q$, $q$No. VMware discontinued the DVX hyperconverged hardware and software line effective immediately in August 2020, about a month after closing the acquisition.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$What happened to Datrium's disaster recovery product$q$, $q$Its disaster-recovery-as-a-service technology was relaunched under the name VMware Cloud Disaster Recovery, which now works with any VMware vSphere-supported storage rather than requiring Datrium hardware.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$How much did VMware pay to acquire Datrium$q$, $q$VMware's purchase price, net of cash acquired, was approximately 137 million US dollars, consisting mainly of about 25 million dollars in identifiable intangible assets and roughly 91 million dollars in goodwill.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Who owns Datrium's technology now$q$, $q$VMware itself was acquired by Broadcom in November 2023, so the surviving Datrium-derived disaster-recovery technology now sits within Broadcom's VMware product portfolio.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$When was Datrium founded and where was it based$q$, $q$Datrium was founded in 2012 and was headquartered in Sunnyvale, California, prior to its 2020 acquisition by VMware.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Is there support for legacy Datrium DVX deployments$q$, $q$VMware wound down support for existing DVX deployments by 2023, so legacy Datrium hardware in production today is effectively unsupported.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$What should I evaluate instead of Datrium in 2026$q$, $q$Buyers researching hybrid cloud disaster recovery today should evaluate VMware Cloud Disaster Recovery directly, along with other current DRaaS vendors, rather than looking for Datrium as a standalone purchase.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Historical and competitive research$q$, $q$Useful for understanding the lineage of VMware Cloud Disaster Recovery and how converged infrastructure vendors have consolidated into larger platforms.$q$, $q$Analysts and IT researchers studying the hyperconverged infrastructure market$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Legacy deployment audits$q$, $q$Organizations still running old Datrium DVX hardware can use this profile to understand why support has ended and plan a migration.$q$, $q$IT operations teams managing aging on-premises infrastructure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$Due diligence on VMware's disaster recovery lineage$q$, $q$Helps buyers evaluating VMware Cloud Disaster Recovery understand the underlying technology's origin at Datrium.$q$, $q$Enterprise architects evaluating disaster-recovery-as-a-service vendors$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$what-datrium-built$q$, $q$What Datrium Built$q$, 2, ARRAY[$q$Datrium's core product, DVX, was a converged infrastructure system that split compute and data management between on-premises hardware and a cloud-connected control plane, letting enterprises run VMware virtual machines locally while pushing backup and disaster-recovery data to the cloud.$q$, $q$The company later built a standalone disaster-recovery-as-a-service product aimed at protecting VMware vSphere environments by replicating workloads off-premises without requiring a full parallel data center.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$vmware-acquisition-and-shutdown$q$, $q$The VMware Acquisition and Product Shutdown$q$, 2, ARRAY[$q$VMware announced its intent to acquire Datrium on July 1, 2020, and closed the deal later that year for approximately 137 million US dollars net of cash acquired, primarily to bolster its own disaster-recovery-as-a-service portfolio.$q$, $q$Barely a month after closing, VMware discontinued the Datrium DVX hyperconverged hardware and software line, stopped taking new hardware orders, and wound down support for existing deployments over the following years, effectively ending Datrium as an independent product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbf78e8a-26c7-4d63-a7b4-b3b2f814c06a', $q$where-the-technology-lives-now$q$, $q$Where Datrium's Technology Lives Today$q$, 2, ARRAY[$q$Only Datrium's disaster-recovery-as-a-service technology survived the acquisition, relaunched under the name VMware Cloud Disaster Recovery, which works with standard VMware vSphere-supported storage rather than requiring proprietary Datrium hardware.$q$, $q$Following Broadcom's acquisition of VMware in November 2023, that surviving technology now sits within Broadcom's VMware Cloud Foundation and disaster-recovery product lines rather than being sold under the Datrium name.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Visual ER diagram builder$q$, $q$Design database schemas on a drag-and-drop canvas similar to building a UML diagram, without writing raw SQL.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Forward engineering to SQL$q$, $q$Generate a ready-to-run SQL script for MySQL, MS SQL, PostgreSQL, Oracle, or SQLite in one click from a finished model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Reverse engineering$q$, $q$Import an existing MySQL, PostgreSQL, or Oracle database and automatically generate its diagram.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Team collaboration and sharing$q$, $q$Share cloud-stored models with teammates for editing or viewing, with live commenting on the diagram itself.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Templates and autocomplete$q$, $q$Start from ready-made templates and use data-type autocomplete and automatic sorting to speed up modeling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Revision history and one-click restore$q$, $q$Every change is versioned, so teams can roll back to any earlier state of a model instantly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Cloning and duplication$q$, $q$Duplicate an existing model or table structure to quickly start variations of a schema.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Image and PDF export$q$, $q$Export finished diagrams as images or PDFs for documentation, presentations, or stakeholder review.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Free tier is genuinely usable for small projects with two models and ten tables per model$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Generates production-ready SQL for several major database engines in one click$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Runs entirely in the browser with no software installation required$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Free plans for students, educators, non-profits, and open-source contributors extend full functionality at no cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Team collaboration and live commenting are included on every plan, not gated to higher tiers$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Auto-save plus full revision history reduces the risk of losing design work$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Reverse engineering is limited to MySQL, PostgreSQL, and Oracle, excluding MS SQL and SQLite$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Free and Basic plans have relatively low model and table caps compared to some competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Company details such as headquarters and team size are not publicly disclosed, which may concern enterprise buyers doing vendor due diligence$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$As a browser-based tool, it depends on a stable internet connection for editing and saving$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Does not appear to offer an on-premises or self-hosted deployment option for teams with strict data residency requirements$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Advanced database-specific features supported by dedicated desktop modeling tools may not all be available$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Is DB Designer free to use$q$, $q$Yes, DB Designer has a free Starter plan supporting up to two database models with ten tables per model, and free specialty plans for students, educators, non-profits, and open-source contributors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$How much does DB Designer cost$q$, $q$Paid plans start at 9 US dollars per month for the Basic plan (five models, twenty-five tables per model), with an Unlimited plan at 17 US dollars per month for unlimited models and tables.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Which databases does DB Designer support$q$, $q$It can forward-engineer SQL for MySQL, MS SQL, PostgreSQL, Oracle, and SQLite, and it supports reverse engineering from MySQL, PostgreSQL, and Oracle.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Can I collaborate with a team in DB Designer$q$, $q$Yes, cloud-stored models can be shared with teammates by email for editing or viewing, and collaborators can leave live comments directly on the diagram.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Does DB Designer offer a free plan for students$q$, $q$Yes, current students and educators can apply for a free Academic plan with unlimited models and tables.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Can I export my database diagrams$q$, $q$Yes, models can be exported as images or PDFs for documentation or presentations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Does DB Designer support version history$q$, $q$Yes, changes are auto-saved and a full revision history allows one-click restoration of any prior version.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Is there a contract or lock-in with paid plans$q$, $q$No, the company states plans can be cancelled, upgraded, or downgraded at any time with no hidden fees or long-term contracts.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Prototyping a new application's database schema$q$, $q$Developers can visually plan tables and relationships before writing any SQL, then generate implementation-ready scripts.$q$, $q$Backend developers and solo founders building new applications$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Documenting an existing production database$q$, $q$Teams can reverse engineer a live MySQL, PostgreSQL, or Oracle database into a visual diagram for onboarding or audits.$q$, $q$Database administrators and technical writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Classroom and coursework database design$q$, $q$Students and educators can use the free Academic plan to design and iterate on schemas for coursework without cost.$q$, $q$Computer science students and instructors$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Cross-functional schema review$q$, $q$Product and engineering teams can share a model for view-only feedback and comments before implementation.$q$, $q$Cross-functional product and engineering teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["2 database models","10 tables per model","Team collaboration","Forward and reverse engineering"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Basic$q$, $q$9 US dollars$q$, $q$per month$q$, NULL, $q$["5 database models","25 tables per model","Team collaboration","Revision history"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Unlimited$q$, $q$17 US dollars$q$, $q$per month$q$, NULL, $q$["Unlimited database models","Unlimited tables per model","Team collaboration","Revision history"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Academic$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited models and tables","For current students and educators only"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Non-Profit$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited models and tables","For qualifying non-profit organizations only"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited models and tables","For contributors of open-source projects only"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$core-workflow$q$, $q$How DB Designer Works$q$, 2, ARRAY[$q$DB Designer centers on a visual, UML-style canvas where users build entity-relationship diagrams representing tables, columns, data types, and relationships, either from scratch, from a template, or by reverse engineering an existing MySQL, PostgreSQL, or Oracle database.$q$, $q$Once a model is finished, the tool forward-engineers it into a one-click SQL script targeted at MySQL, MS SQL, PostgreSQL, Oracle, or SQLite, letting teams design first and generate implementation-ready SQL rather than writing schema definitions by hand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$collaboration-and-history$q$, $q$Collaboration and Version History$q$, 2, ARRAY[$q$Designs are stored in the cloud and can be shared with teammates for either editing or view-only access, with live commenting available once collaborators are added by email, which supports asynchronous schema review.$q$, $q$Every change is auto-saved, and a full revision history lets teams roll back to any prior version with one click, reducing the risk of losing work during iterative schema design.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d849eb46-cb77-427d-92b2-77f0e11c7f95', $q$pricing-tiers$q$, $q$Pricing Tiers and Free Access Programs$q$, 2, ARRAY[$q$The free Starter plan caps users at two models and ten tables per model, while the paid Basic plan (9 US dollars per month) raises that to five models and twenty-five tables, and the Unlimited plan (17 US dollars per month) removes those caps entirely.$q$, $q$Students, educators, qualifying non-profit organizations, and open-source contributors can apply for free plans that match the Unlimited tier's model and table limits, extending full functionality to those groups at no cost.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Full IPv4 and IPv6 coverage$q$, $q$Maps the entire IPv4 and IPv6 address space across more than 45 million address blocks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$City, region, and country geolocation$q$, $q$Returns granular location data including GPS coordinates, district, and zip code for supported addresses.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$ISP and network intelligence$q$, $q$Core and Extended tiers add autonomous system number, ISP name, organization, and connection type.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Proxy, crawler, and threat detection$q$, $q$The Extended tier flags proxy usage, crawler traffic, and assigns a threat-level score for security and fraud use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Multi-language localization$q$, $q$Supports place-name localization in more than fifty languages via the API and a smaller set of major languages in offline MMDB databases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Real-time API and offline databases$q$, $q$Offers both a queryable REST API and downloadable database files for self-hosted, low-latency integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Batch query support$q$, $q$Allows batch lookups of multiple IP addresses in a single request on paid plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Free Lite database$q$, $q$Provides a free, lower-accuracy IP-to-City Lite database for non-commercial or budget-constrained use.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Covers the entire global IPv4 and IPv6 address space with reported high accuracy at country and city level$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Offers both a live API and downloadable offline databases, giving integration flexibility$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Supports localization in more than fifty languages, unusually broad for a geolocation provider$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Tiered Basic, Core, and Extended data levels let customers pay only for the depth of data they need$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Free Lite database option makes it accessible for small or non-commercial projects$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Enterprise plan includes dedicated infrastructure and a 99.99 percent uptime guarantee$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Full pricing for Core, Extended, and offline database licenses is not uniformly published and often requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Company size and detailed corporate background are not publicly disclosed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Starter and Premium plan request caps may be limiting for rapidly scaling applications$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$IP geolocation data is inherently probabilistic and can be inaccurate for VPN, mobile, or corporate NAT traffic regardless of vendor$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Offline MMDB localization covers fewer languages than the live API's fifty-plus languages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$As a smaller, France-based provider, it has less brand recognition than larger competitors like MaxMind$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$What is DB-IP used for$q$, $q$DB-IP is used to determine the geographic location, network provider, and security risk associated with an IP address, commonly for content localization, fraud prevention, analytics, and access control.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$How much does DB-IP cost$q$, $q$The Basic API Starter plan costs about 8.29 euros per month, Premium is about 99.90 euros per month, and Enterprise is about 499.90 euros per month, based on daily request volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Is there a free version of DB-IP$q$, $q$Yes, DB-IP offers a free downloadable IP-to-City Lite database for non-commercial or lower-accuracy use cases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$How accurate is DB-IP's geolocation data$q$, $q$The company reports accuracy above 97 percent at the city level and 99.99 percent at the country level worldwide.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Does DB-IP support IPv6$q$, $q$Yes, DB-IP covers the entire IPv6 address space in addition to IPv4.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Can I download DB-IP's database instead of using the API$q$, $q$Yes, DB-IP offers downloadable offline database files in addition to its real-time API, suitable for self-hosted, low-latency integrations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$What is the difference between DB-IP's Basic, Core, and Extended tiers$q$, $q$Basic returns core location data, Core adds ISP and network data, and Extended adds proxy, crawler, and threat-level detection on top of Core.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Who operates DB-IP$q$, $q$DB-IP is operated by Eris Networks S.A.S, headquartered in Perros-Guirec, France, and has offered geolocation services since 2010.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Website content localization$q$, $q$Automatically serve region-appropriate language, currency, or content based on a visitor's IP-derived location.$q$, $q$Web developers and e-commerce teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Fraud and risk scoring$q$, $q$Combine proxy detection and threat-level data from the Extended tier to flag suspicious sign-ups or transactions.$q$, $q$Trust and safety and fraud-prevention teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Analytics and audience insights$q$, $q$Enrich web or app analytics with visitor city, region, and ISP data for reporting and segmentation.$q$, $q$Marketing and product analytics teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Access control and compliance$q$, $q$Restrict or allow access to content or services based on country or region using geolocation lookups.$q$, $q$Compliance and platform engineering teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Basic API Starter$q$, $q$8.29 euros$q$, $q$per month$q$, NULL, $q$["2,000 to 50,000 requests per day","50+ language localization","Batch queries up to 256 IPs","Single CORS domain","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Basic API Premium$q$, $q$99.90 euros$q$, $q$per month$q$, NULL, $q$["200,000 to 1,000,000 requests per day","Up to 5 CORS domains","99.95% uptime guarantee","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$Basic API Enterprise$q$, $q$499.90 euros$q$, $q$per month$q$, NULL, $q$["Unlimited requests per day","Unlimited batch queries","Unlimited CORS domains","99.99% uptime guarantee","Dedicated infrastructure","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$data-coverage-and-accuracy$q$, $q$Data Coverage and Accuracy$q$, 2, ARRAY[$q$DB-IP's database covers the entire IPv4 and IPv6 address space with more than 45 million address blocks across over 2 million unique locations in more than 215,000 cities worldwide, and the company reports accuracy above 97 percent at the city level and 99.99 percent at the country level.$q$, $q$Data is refreshed and delivered either through a real-time API or as downloadable offline database files, giving customers flexibility between live lookups and self-hosted, low-latency integrations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$data-tiers$q$, $q$Basic, Core, and Extended Data Tiers$q$, 2, ARRAY[$q$The Basic tier covers core location data such as country, city, GPS coordinates, and time zone. The Core tier adds ISP and autonomous system network data on top of Basic. The Extended tier layers on security signals like proxy, crawler, and threat-level detection.$q$, $q$This tiered structure lets customers pay only for the depth of data their use case requires, from simple content localization up to fraud-prevention and access-control scenarios that need network and threat intelligence.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', $q$api-pricing-detail$q$, $q$Basic API Pricing Breakdown$q$, 2, ARRAY[$q$The Starter Basic API plan costs approximately 8.29 euros per month for 2,000 to 50,000 requests per day, the Premium plan costs approximately 99.90 euros per month for 200,000 to 1,000,000 requests per day, and the Enterprise plan costs approximately 499.90 euros per month for unlimited daily requests.$q$, $q$Higher plans add practical guarantees for production use, including higher uptime SLAs, more CORS domains, dedicated infrastructure at the Enterprise level, and priority support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6776ca43-0c85-42d6-ab67-97d33ece86d2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Modular plugin system$q$, $q$Nearly every feature, from decoders to UI behavior, is delivered as an independently enableable plugin.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Wide native format support$q$, $q$Plays MP3, FLAC, OGG, APE, WAV, AAC, ALAC, WMA, and many tracker and chiptune formats like SID, MOD, and NSF out of the box.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Gapless playback and CUE sheet handling$q$, $q$Natively handles CUE sheets for seamless, gapless playback of albums ripped as a single audio file.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Album art plugin$q$, $q$Fetches cover art from multiple local and online sources automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Play from ZIP archives$q$, $q$Can play audio files directly from within ZIP archives without extracting them first.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$On-screen notifications$q$, $q$An OSD Notify plugin displays track information on screen when a song changes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Cross-platform builds$q$, $q$Available primarily for Linux and other Unix-like systems, with additional builds for Windows and macOS.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Customizable GTK3 interface$q$, $q$Later versions default to a GTK3-based interface that can be themed and rearranged to suit user preference.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Completely free and open source with no paid tiers or licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Supports an unusually broad range of audio formats, including niche tracker and chiptune formats$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Highly customizable through its plugin architecture, letting users tailor the feature set precisely$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Lightweight and resource-efficient compared to many full-featured media players$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Native CUE sheet support gives accurate gapless playback for single-file album rips$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Actively used and packaged across most major Linux distributions$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Interface and setup can feel less polished or intuitive than mainstream commercial or cross-platform players$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Plugin-based customization requires more manual configuration than an out-of-the-box all-in-one player$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Windows and macOS builds receive less attention than the primary Linux target platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$As a volunteer-maintained open-source project, release cadence and support responsiveness can vary$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Lacks the built-in streaming-service integrations that many modern commercial music players offer$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Documentation for advanced plugin configuration is less comprehensive than for mainstream media players$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Is DeaDBeeF free$q$, $q$Yes, DeaDBeeF is completely free and open source with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$What platforms does DeaDBeeF support$q$, $q$It is primarily built for Linux and other Unix-like systems, with additional builds available for Windows and macOS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$What audio formats does DeaDBeeF play$q$, $q$It natively supports MP3, FLAC, OGG, APE, WAV, WavPack, AAC, ALAC, Musepack, TTA, WMA, audio CDs, and tracker or chiptune formats like SID, NSF, MOD, and S3M, with even more formats available via plugins.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Why is DeaDBeeF plugin-based$q$, $q$Its modular design lets users enable only the features and format decoders they actually need, keeping the core player lightweight while still allowing deep customization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Does DeaDBeeF support gapless playback$q$, $q$Yes, it has native CUE sheet handling that supports gapless playback for albums ripped as a single audio file.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$When was DeaDBeeF first released$q$, $q$It was first published in August 2009.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Can DeaDBeeF play music from ZIP files$q$, $q$Yes, a plugin allows it to play audio files directly from ZIP archives without extracting them.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Is DeaDBeeF actively maintained in 2026$q$, $q$Yes, it continues to receive incremental updates from its community maintainers, with recent versions adding features like FLAC network streaming and a lyrics plugin.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Lightweight Linux music playback$q$, $q$Provides a low-resource-usage audio player for Linux desktop users who want speed and stability over heavy features.$q$, $q$Linux desktop users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Playing niche and legacy audio formats$q$, $q$Lets retro-gaming and chiptune enthusiasts play tracker and console sound formats like MOD, NSF, and SID natively.$q$, $q$Chiptune and retro-format audio enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Highly customized listening setup$q$, $q$Allows power users to build a tailored player experience by selectively enabling only the plugins they need.$q$, $q$Advanced Linux users and audio hobbyists$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$Managing large local music libraries$q$, $q$Handles large personal music collections with CUE sheet support and broad format compatibility without needing format conversion.$q$, $q$Users with extensive local audio archives$q$, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$plugin-architecture$q$, $q$Plugin-Based Architecture$q$, 2, ARRAY[$q$DeaDBeeF's defining feature is that nearly all of its functionality, from format decoding to notifications to album-art fetching, is delivered through individually enableable plugins rather than being built into a fixed core application.$q$, $q$This means users are not locked into a single feature set; they can strip the player down to a minimal, lightweight decoder and interface, or extend it with a wide range of optional plugins depending on what they need.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$format-support$q$, $q$Audio Format Support$q$, 2, ARRAY[$q$DeaDBeeF natively supports a very wide range of formats including MP3, FLAC, OGG, APE, WAV, WavPack, AAC, ALAC, Musepack, TTA, WMA, and audio CDs, plus tracker and chiptune formats like SID, NSF, MOD, S3M, and VGM.$q$, $q$Through additional plugins built on libraries such as ffmpeg, Game Music Emu, and libsndfile, it can decode an even broader set of formats, making it a popular choice for users with large or unusually formatted music collections.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', $q$platform-and-distribution$q$, $q$Platforms and How to Get It$q$, 2, ARRAY[$q$DeaDBeeF is primarily distributed for Linux and other Unix-like systems, with builds also available for Windows and macOS, and it is packaged in the repositories of many major Linux distributions as well as through community PPAs for Ubuntu.$q$, $q$As a free, open-source project hosted on SourceForge and elsewhere, it has no purchase process, license fees, or paid tiers; users simply download or install it through their distribution's package manager.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e41fd154-3522-4aa5-8b80-838519aa792f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Simple check-in monitoring$q$, $q$Detects missed or failed scheduled jobs by watching for an expected HTTP ping after each successful run.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Works with any scheduler$q$, $q$Supports cron, Heroku Scheduler, CI/CD pipelines, and any custom process that can send an HTTP request.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Configurable check-in intervals$q$, $q$Lets teams define expected run frequency and grace periods per monitored job.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Error status detection$q$, $q$Smart Alerts and Error Notices on higher plans flag jobs that check in but report a failure rather than only detecting silence.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$API access$q$, $q$Provides an API for programmatically creating and managing snitches, included on all paid plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Unlimited team members on paid plans$q$, $q$Scales pricing by number of monitored jobs rather than number of users.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Integrations$q$, $q$Routes alerts into common channels such as email and chat or webhook-based notification tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Field Agent feature$q$, $q$An additional monitoring capability included starting on the Little Birdy plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Very simple, focused setup that solves the specific problem of silently failing scheduled jobs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Pricing scales by number of monitored jobs rather than by seat, which favors larger teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Works with virtually any scheduler or periodic process capable of an outbound HTTP ping$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Free plan is available for monitoring a single job at no cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Higher tiers add error-status detection, not just silence detection, via Smart Alerts$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Long operating history since 2012 under a stable, established web development studio$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Paid plan snitch limits (3, 100, or 300) may require jumping a tier as monitoring needs grow incrementally$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Does not appear to publish a per-seat or usage-based enterprise pricing calculator online, requiring direct contact for custom needs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Company size and detailed internal metrics are not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Focuses narrowly on check-in monitoring rather than broader application performance or infrastructure monitoring$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Free plan is limited to a single monitored job, which is quite restrictive beyond personal projects$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$On-premise hosting is not offered as a standard published plan and requires a custom conversation with sales$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$What does Dead Man's Snitch do$q$, $q$It monitors cron jobs and other scheduled tasks by watching for an expected check-in ping, alerting the team when a job fails to run or check in on time.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$How much does Dead Man's Snitch cost$q$, $q$There is a free plan for one monitored job, with paid plans starting at 5 US dollars per month for 3 jobs up to 49 US dollars per month for 300 jobs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Does Dead Man's Snitch work with Heroku Scheduler$q$, $q$Yes, it explicitly supports monitoring cron jobs, Heroku Scheduler tasks, and any other scheduled process capable of sending an HTTP check-in.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Who owns Dead Man's Snitch$q$, $q$It was founded in 2012 and acquired by Collective Idea, a web development studio based in Holland, Michigan, in July 2013.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Does Dead Man's Snitch charge per team member$q$, $q$No, paid plans include unlimited team members and instead scale pricing by the number of monitored jobs, called snitches.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Can Dead Man's Snitch detect a job that ran but failed$q$, $q$Yes, on higher plans Smart Alerts and Error Notices can flag jobs that checked in but reported an error, not just jobs that went silent.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Is there an API for Dead Man's Snitch$q$, $q$Yes, API access is included on all paid plans for programmatically managing snitches.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$What integrations does Dead Man's Snitch support$q$, $q$It integrates with common alerting channels including email and chat or webhook-based notification tools on its higher plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Monitoring nightly backup jobs$q$, $q$Alerts a team immediately if a scheduled database or file backup job fails to run or complete.$q$, $q$DevOps and infrastructure engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Watching data pipeline and ETL jobs$q$, $q$Confirms scheduled data syncs and ETL processes complete on time, catching silent failures before they cause downstream data gaps.$q$, $q$Data engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Verifying scheduled report generation$q$, $q$Ensures automated reports, invoices, or emails generated on a schedule actually run as expected.$q$, $q$SaaS teams and backend developers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Tracking Heroku Scheduler tasks$q$, $q$Monitors Heroku Scheduler jobs specifically, filling a gap since Heroku itself does not natively alert on missed scheduled runs.$q$, $q$Teams deploying on Heroku$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Lone Snitch$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 monitored job"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Little Birdy$q$, $q$5 US dollars$q$, $q$per month$q$, NULL, $q$["3 snitches","Basic intervals","API access","Field Agent","Unlimited team members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Private Eye$q$, $q$19 US dollars$q$, $q$per month$q$, NULL, $q$["100 snitches","Enhanced intervals","API access","Field Agent","Unlimited team members","Integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$Surveillance Van$q$, $q$49 US dollars$q$, $q$per month$q$, NULL, $q$["300 snitches","Enhanced intervals","API access","Field Agent","Unlimited team members","Integrations","Smart Alerts","Error Notices"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$how-it-works$q$, $q$How Dead Man's Snitch Works$q$, 2, ARRAY[$q$Each monitored job is assigned a unique URL, called a snitch, that the job is configured to ping after it completes successfully. If the expected ping does not arrive within the configured time window, Dead Man's Snitch sends an alert.$q$, $q$This check-in model works for any process capable of making an outbound HTTP request on success, including traditional cron jobs, Heroku Scheduler tasks, CI/CD pipeline steps, and custom background workers, not just Unix cron specifically.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$pricing-structure$q$, $q$How Pricing Scales$q$, 2, ARRAY[$q$Pricing is based primarily on the number of snitches, or monitored jobs, rather than the number of team members, with a free plan for a single job and paid plans ranging from 5 to 49 US dollars per month covering 3 to 300 snitches.$q$, $q$All paid plans include API access and unlimited team members, making the pricing model notably cost-effective for larger teams that need many people to have visibility into a moderate number of monitored jobs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8f1f6581-f42c-4ff4-a4aa-54f0bd634a79', $q$company-background$q$, $q$Company Background$q$, 2, ARRAY[$q$Dead Man's Snitch was founded in 2012 and acquired by Collective Idea, a web development studio based in Holland, Michigan, on July 30, 2013, and has operated as one of Collective Idea's products since the acquisition.$q$, $q$The service has maintained a consistent focus on simple, reliable job check-in monitoring rather than expanding into a broader observability platform, which has helped it remain a straightforward, well-regarded tool among developers over more than a decade of operation.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$AI-powered deal data ingestion$q$, $q$Extracts and structures data automatically from offering memoranda and other unstructured deal documents.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Comparables database$q$, $q$Provides a built-in database of comparable deals with analytics and reporting to support underwriting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Due diligence workflows$q$, $q$Coordinates distributed teams around tasks, documents, and approvals tied to a single deal record.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Pipeline and investment committee management$q$, $q$Systematizes how deals move through stages toward a final investment decision.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Microsoft Office compatibility$q$, $q$Integrates with Excel-based underwriting workflows that many real estate teams already rely on.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Open API and BI integration$q$, $q$Enterprise plan customers can connect Dealpath to business intelligence tools and other systems via an open API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Asset management platform integration$q$, $q$Connects deal-stage data with post-close asset management systems for continuity across the investment lifecycle.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$SOC 2 Type 2 security$q$, $q$Meets enterprise security compliance standards expected by institutional real estate and financial services buyers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Purpose-built specifically for institutional commercial real estate deal workflows rather than generic project management$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$AI-powered data ingestion reduces manual data entry from offering memoranda and deal documents$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Strong Microsoft Office compatibility fits existing Excel-centric underwriting workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$SOC 2 Type 2 certification supports enterprise security and compliance requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$High-touch onboarding includes a dedicated Customer Success Manager and white-glove implementation$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$No minimum deal volume required, only a minimum user count$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Pricing is not published and requires a sales demo and custom quote, adding friction for quick evaluation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Minimum of five users per account makes it impractical for very small teams or solo investors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Company size and detailed internal metrics are not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$White-glove implementation typically takes six to eight weeks, which is a longer onboarding cycle than self-serve tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Enterprise-focused feature set may be more than smaller firms need, pushing them toward a higher-cost tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$As an enterprise sales-led product, it lacks a free trial or self-serve entry point for prospective users to test independently$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$What does Dealpath do$q$, $q$Dealpath is a deal management platform that helps institutional commercial real estate firms source, track, underwrite, and close acquisitions, dispositions, development projects, and debt transactions in one system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$How much does Dealpath cost$q$, $q$Dealpath does not publish fixed pricing; it sells Professional and Enterprise plans on a custom-quoted basis after a sales demo, with a minimum of five users required per account.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Who is Dealpath built for$q$, $q$It is built for institutional real estate organizations such as investment managers, developers, brokerages, and lenders that need centralized deal tracking across distributed teams.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Does Dealpath integrate with Excel$q$, $q$Yes, the platform emphasizes Microsoft Office compatibility so teams can continue Excel-based underwriting while syncing data into Dealpath.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$What is the difference between Dealpath's Professional and Enterprise plans$q$, $q$The Enterprise plan adds capabilities such as business intelligence integration, asset management platform integration, single sign-on, an open API, and sandbox environments on top of the Professional plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Where is Dealpath headquartered$q$, $q$Dealpath is dual-headquartered in San Francisco, California and New York, New York, with additional offices in Toronto and Austin.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$When was Dealpath founded$q$, $q$Dealpath launched in 2014.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Does Dealpath offer implementation support$q$, $q$Yes, all plans include a dedicated Customer Success Manager and white-glove implementation that typically takes six to eight weeks, plus ongoing training and support.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Institutional acquisition pipeline tracking$q$, $q$Centralizes sourcing and underwriting for real estate investment managers evaluating many potential acquisitions at once.$q$, $q$Institutional real estate investment managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Cross-team due diligence coordination$q$, $q$Coordinates legal, finance, and asset management teams around a shared due-diligence checklist and document set for a single deal.$q$, $q$Real estate due diligence and legal teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Development project deal tracking$q$, $q$Manages development-stage deal data alongside acquisitions and dispositions in the same centralized pipeline.$q$, $q$Real estate developers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Debt transaction and lender workflows$q$, $q$Tracks debt transaction pipelines alongside equity deals for lenders and firms with mixed investment strategies.$q$, $q$Commercial real estate lenders and debt investors$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Professional$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["AI-powered deal data ingestion","Comparables database with analytics","Due diligence workflows","Pipeline and investment committee management","SOC 2 Type 2 security","Microsoft Office compatibility","Minimum 5 users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Contact sales$q$, NULL, $q$["Everything in Professional","Contextual deal data in investor reporting","Business intelligence integration","Asset management platform integration","Single sign-on (SSO)","Open API","Sandbox environments","Early access to betas"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$what-dealpath-does$q$, $q$What Dealpath Does$q$, 2, ARRAY[$q$Dealpath centralizes the full commercial real estate deal lifecycle, from sourcing and underwriting through due diligence, investment committee decisioning, and closing, covering acquisitions, dispositions, development, and debt transactions in one system.$q$, $q$The platform is built specifically for institutional real estate organizations that need distributed teams working from a single, shared record of deal activity, rather than scattered spreadsheets, email threads, and disconnected documents.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$core-capabilities$q$, $q$Core Platform Capabilities$q$, 2, ARRAY[$q$Key capabilities include AI-powered ingestion of unstructured deal documents, a comparables database with analytics and reporting, collaborative due-diligence workflows, and pipeline management tools that systematize how deals progress toward an investment committee decision.$q$, $q$Dealpath also emphasizes compatibility with Microsoft Office, letting Excel-centric underwriting workflows continue while syncing into the centralized platform, and it holds SOC 2 Type 2 certification for enterprise security compliance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('51e92830-5fd4-48b4-b404-c9667fbccbf1', $q$pricing-and-onboarding$q$, $q$Pricing and Onboarding Model$q$, 2, ARRAY[$q$Dealpath sells Professional and Enterprise plans on a custom-quoted basis, requiring a minimum of five users per account with no minimum deal volume, and prospective customers must request a demo to receive pricing.$q$, $q$All plans include a dedicated Customer Success Manager and white-glove implementation typically taking six to eight weeks, reflecting a high-touch enterprise onboarding process rather than instant self-serve signup.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Fake SMTP server$q$, $q$Intercepts outgoing application emails during development so they never reach real inboxes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$HTML and plain-text preview$q$, $q$View captured emails in either rendered HTML or raw plain-text format directly in the browser.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Downloadable .EML files$q$, $q$Export captured emails as standard .EML files for use in other clients or for archiving.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Email forwarding$q$, $q$Manually forward a captured test email to a real address for a final visual check.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Shared team mailboxes$q$, $q$Organize captured emails by project and share mailbox access with teammates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Public share links$q$, $q$Generate a public link to an individual captured email for quick review or bug reports.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Free plan for open-source projects$q$, $q$Offers Gold-tier functionality at no cost specifically for open-source project maintainers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Team collaboration tools$q$, $q$Supports multiple team members per project with role-based access across plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Prevents test emails from accidentally reaching real users during development$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Supports both HTML and plain-text preview plus .EML export for thorough email QA$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Shared mailboxes and public links make collaborative email review straightforward$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Free tier is available for open-source projects with fuller functionality than the standard free plan$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Straightforward SMTP-based integration that works with most application mail-sending code$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Per-user pricing on paid plans is relatively low compared to many developer-tool subscriptions$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$The Free plan converts to a paid rate after a two-week trial period, which may surprise users expecting a permanently free tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Company founding year, exact headquarters, and team size are not clearly published on the official site$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Premium plan pricing is not publicly listed and likely requires contacting sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Storage limits on Free and Gold plans (10MB and 1GB) may be restrictive for high-volume testing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Roadmap items like IMAP integration and spam-score rating were described as upcoming rather than currently available$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Less brand recognition and community documentation compared to larger competitors like Mailtrap$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$What is debugmail.io used for$q$, $q$It is used as a fake SMTP server to capture and inspect outgoing emails from an application during development, so test emails never reach real inboxes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Is debugmail.io free$q$, $q$There is a free plan with 1 project and 2 team members, though the site notes a two-week trial period after which usage converts to a paid rate of about 2 US dollars per user per month; a free Gold-tier plan is also offered for open-source projects.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$How much do paid debugmail.io plans cost$q$, $q$The Gold plan costs about 5 US dollars per user per month, while Premium plan pricing is not publicly listed and requires contacting the company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Can I forward test emails to a real inbox$q$, $q$Yes, debugmail.io supports forwarding captured test emails to a real email address for a final review, with daily forwarding limits that vary by plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Does debugmail.io support team collaboration$q$, $q$Yes, projects and mailboxes can be shared among team members, and individual captured emails can be shared via public links.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Can I download captured emails from debugmail.io$q$, $q$Yes, captured emails can be downloaded as standard .EML files for use in other email clients or for archiving.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Who operates debugmail.io$q$, $q$The service is operated by WBTech; the company does not publish a founding year or detailed headquarters information on its official site.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$What features are planned for debugmail.io$q$, $q$The company has referenced upcoming IMAP integration, spam-score rating, and a dedicated mail-client-style viewer as planned additions.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Testing transactional email templates$q$, $q$Verifies that password resets, order confirmations, and other transactional emails render correctly before shipping to production.$q$, $q$Backend and full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$QA review of email content and formatting$q$, $q$Lets QA teams inspect captured HTML and plain-text emails for bugs without needing access to real user inboxes.$q$, $q$QA engineers and testers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Safe staging environment email testing$q$, $q$Prevents staging or QA environments from accidentally sending real emails to customers by capturing all outgoing mail.$q$, $q$DevOps and release engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Open-source project email testing$q$, $q$Provides open-source maintainers a free way to test email-sending features in their projects without cost.$q$, $q$Open-source project maintainers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Free$q$, $q$Free (converts to paid rate after 2-week trial)$q$, $q$per user per month$q$, NULL, $q$["1 project","2 team members","Unlimited test emails per day","1 forwarding email per day","10MB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Gold$q$, $q$5 US dollars$q$, $q$per user per month$q$, NULL, $q$["Unlimited projects","20 team members","Unlimited test emails per day","100 forwarding emails per day","1GB storage","1 forwarding rule per project"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Premium$q$, $q$Contact for pricing$q$, $q$per user per month$q$, NULL, $q$["Unlimited projects and team members","Unlimited emails and forwarding","5GB storage","20 forwarding rules per project"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Gold-tier functionality","For open-source project maintainers only"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$what-it-does$q$, $q$What debugmail.io Does$q$, 2, ARRAY[$q$debugmail.io acts as a fake SMTP server that intercepts outgoing emails from an application in development or staging environments, capturing them in a web-based mailbox instead of delivering them to real recipients.$q$, $q$This lets developers and QA teams verify email content, formatting, and links safely, without the risk of sending test emails to real customers or cluttering personal inboxes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$collaboration-features$q$, $q$Team and Project Features$q$, 2, ARRAY[$q$Emails are organized by project, and mailboxes can be shared with teammates, with public links available for individual captured emails to support quick review and bug reporting.$q$, $q$Captured emails can be viewed in HTML or plain text, downloaded as .EML files, and optionally forwarded to a real email address for a final check before release.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e9618ae-8e11-442d-bbb3-7bbaa72af0f4', $q$pricing-tiers$q$, $q$Free, Gold, and Premium Pricing$q$, 2, ARRAY[$q$The Free plan includes 1 project, 2 team members, unlimited test emails per day, and 10MB of storage, though the site notes a two-week trial period after which usage is billed at about 2 US dollars per user per month.$q$, $q$The Gold plan (about 5 US dollars per user per month) raises limits to 20 team members and unlimited projects, while the Premium plan removes remaining caps on projects, team members, emails, and forwarding rules; a free Gold-tier plan is also available specifically for open-source projects.$q$]::text[], 2);
